/**
 * Business Information Checker Utility
 * 
 * Provides functions to check if business information is complete
 * for verification purposes. Checks all required fields as defined
 * in the Business Details Form.
 */

import { businessService } from '@/features/settings/services';
import { logger } from '@/shared/utils/logger.js';

/**
 * All required business information fields
 * These must be completed before users can access Level 2 and Level 3 verification
 */
export const REQUIRED_BUSINESS_FIELDS = [
  { key: 'tradingName', apiKey: 'trading_name', label: 'Trading Name', icon: 'business' },
  { key: 'registrationType', apiKey: 'registration_type', label: 'Registration Type', icon: 'description' },
  { key: 'industry', apiKey: 'industry', label: 'Industry', icon: 'work' },
  { key: 'dateOfIncorporation', apiKey: 'date_of_incorporation', label: 'Date of Incorporation', icon: 'event' },
  { key: 'registrationNumber', apiKey: 'registration_number', label: 'Registration Number', icon: 'badge' },
  { key: 'tinNumber', apiKey: 'tin_number', label: 'TIN Number', icon: 'receipt_long' },
  { key: 'businessEmail', apiKey: 'business_email', label: 'Business Email', icon: 'email' },
  { key: 'businessPhone', apiKey: 'business_phone', label: 'Business Phone', icon: 'phone' },
  { key: 'gpsAddress', apiKey: 'gps_address', label: 'GPS Address', icon: 'location_on' }
];

/**
 * Checks if required business information fields are complete
 * @param {string} businessId - The business ID to check
 * @returns {Promise<{isComplete: boolean, missingFields: Array<{key: string, label: string, icon: string}>}>}
 */
export const checkBusinessInfoComplete = async (businessId) => {
  if (!businessId) {
    logger.warn('No businessId provided for business info check');
    return { 
      isComplete: false, 
      missingFields: REQUIRED_BUSINESS_FIELDS.map(f => ({ key: f.key, label: f.label, icon: f.icon }))
    };
  }

  try {
    let info = null;

    // Try API first
    try {
      info = await businessService.getBusinessInfo(businessId);
      logger.debug('Business info from API', { businessId });
    } catch (apiError) {
      logger.warn('API call failed, checking localStorage', { apiError });
      // Fallback to localStorage/userData
      try {
        const userData = JSON.parse(localStorage.getItem('userData') || '{}');
        const businesses = userData?.businesses || [];
        const business = businesses.find(b => b.id === businessId) || businesses[0] || userData?.business || {};
        info = business;
        logger.debug('Business info from localStorage', { businessId });
      } catch (localError) {
        logger.error('Failed to get business info from localStorage', { localError });
      }
    }

    if (!info) {
      logger.warn('No business info found from API or localStorage');
      return { 
        isComplete: false, 
        missingFields: REQUIRED_BUSINESS_FIELDS.map(f => ({ key: f.key, label: f.label, icon: f.icon }))
      };
    }

    // Check all required fields
    const missingFields = [];

    REQUIRED_BUSINESS_FIELDS.forEach(field => {
      // Check multiple possible field names (camelCase, snake_case, nested data)
      const value = info?.[field.apiKey] || 
                   info?.[field.key] || 
                   info?.data?.[field.apiKey] || 
                   info?.data?.[field.key] || 
                   '';
      
      if (String(value || '').trim() === '') {
        missingFields.push({
          key: field.key,
          label: field.label,
          icon: field.icon
        });
      }
    });

    const isComplete = missingFields.length === 0;

    logger.debug('Business info check result', {
      isComplete,
      missingFieldsCount: missingFields.length,
      missingFields: missingFields.map(f => f.key)
    });

    return { isComplete, missingFields };
  } catch (error) {
    logger.error('Failed to check business information', { error, businessId });
    return {
      isComplete: false,
      missingFields: REQUIRED_BUSINESS_FIELDS.map(f => ({ key: f.key, label: f.label, icon: f.icon }))
    };
  }
};
