/**
 * Business Information Required Modal
 * 
 * Industry-standard modal dialog that appears when users try to access
 * locked verification levels. Prompts users to complete business information.
 */

import React, { useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

const BusinessInfoRequiredModal = ({ isOpen, onClose, level }) => {
  const navigate = useNavigate();
  const { t } = useTranslation();

  // Close on Escape key
  useEffect(() => {
    if (!isOpen) {return;}

    const handleEscape = (e) => {
      if (e.key === 'Escape') {
        onClose();
      }
    };

    document.addEventListener('keydown', handleEscape);
    // Prevent body scroll when modal is open
    document.body.style.overflow = 'hidden';

    return () => {
      document.removeEventListener('keydown', handleEscape);
      document.body.style.overflow = 'unset';
    };
  }, [isOpen, onClose]);

  if (!isOpen) {return null;}

  const handleGoToBusinessSettings = () => {
    // Set the active tab in localStorage to ensure the Business tab is opened
    localStorage.setItem('businessSettingsActiveTab', 'business');
    navigate('/settings/business#business');
    onClose();
  };

  const modalContent = (
    <div
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundColor: 'rgba(0, 0, 0, 0.65)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        zIndex: 99999,
        padding: '20px',
        backdropFilter: 'blur(4px)',
        animation: 'fadeIn 0.2s ease-out'
      }}
      onClick={onClose}
    >
      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
        @keyframes slideUp {
          from { 
            opacity: 0;
            transform: translateY(20px);
          }
          to { 
            opacity: 1;
            transform: translateY(0);
          }
        }
      `}</style>
      <div
        style={{
          backgroundColor: '#ffffff',
          borderRadius: '16px',
          maxWidth: '560px',
          width: '100%',
          padding: '40px 32px',
          boxShadow: '0 24px 64px rgba(0, 0, 0, 0.4)',
          position: 'relative',
          border: '1px solid var(--border-primary)',
          animation: 'slideUp 0.3s ease-out',
          maxHeight: '90vh',
          overflowY: 'auto'
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Close Button */}
        <button
          onClick={onClose}
          style={{
            position: 'absolute',
            top: '16px',
            right: '16px',
            background: 'none',
            border: 'none',
            fontSize: '28px',
            color: 'var(--text-muted)',
            cursor: 'pointer',
            padding: '4px',
            lineHeight: 1,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            width: '32px',
            height: '32px',
            borderRadius: '50%',
            transition: 'all 0.2s ease'
          }}
          onMouseOver={(e) => {
            e.target.style.backgroundColor = 'var(--bg-secondary)';
            e.target.style.color = 'var(--text-primary)';
          }}
          onMouseOut={(e) => {
            e.target.style.backgroundColor = 'transparent';
            e.target.style.color = 'var(--text-muted)';
          }}
          aria-label="Close"
        >
          ×
        </button>

        {/* Lock Icon */}
        <div
          style={{
            width: '80px',
            height: '80px',
            borderRadius: '50%',
            backgroundColor: 'var(--warning-bg, rgba(255, 193, 7, 0.15))',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            margin: '0 auto 24px',
            border: '3px solid var(--warning, #FFC107)'
          }}
        >
          <span className="material-symbols-outlined" style={{ fontSize: '48px', color: 'var(--warning, #FFC107)' }}>
            lock
          </span>
        </div>

        {/* Title */}
        <h2
          style={{
            fontSize: '28px',
            fontWeight: '700',
            color: 'var(--text-primary)',
            textAlign: 'center',
            marginBottom: '12px',
            lineHeight: '1.3'
          }}
        >
          {t('verificationLevelLocked', { ns: 'settings', defaultValue: 'Verification Level Locked' })}
        </h2>

        {/* Description */}
        <p
          style={{
            fontSize: '16px',
            color: 'var(--text-secondary)',
            textAlign: 'center',
            marginBottom: '24px',
            lineHeight: '1.6'
          }}
        >
          {t('completeBusinessInfoToUnlockLevel', {
            ns: 'settings',
            level,
            defaultValue: `To proceed with Level ${level} verification for financial transactions, you must complete all required business information fields first.`
          })}
        </p>

        {/* Important Notice */}
        <div
          style={{
            backgroundColor: 'rgba(0, 72, 149, 0.05)',
            border: '1px solid var(--accent)',
            borderRadius: '10px',
            padding: '16px',
            marginBottom: '24px'
          }}
        >
          <div style={{ display: 'flex', alignItems: 'flex-start', gap: '12px' }}>
            <span className="material-symbols-outlined" style={{ fontSize: '24px', color: 'var(--accent)', flexShrink: 0 }}>
              info
            </span>
            <div>
              <p style={{ margin: 0, fontWeight: '600', color: 'var(--text-primary)', fontSize: '14px', marginBottom: '4px' }}>
                {t('financialTransactionRequirement', { ns: 'settings', defaultValue: 'Financial Transaction Requirement' })}
              </p>
              <p style={{ margin: 0, color: 'var(--text-secondary)', fontSize: '13px', lineHeight: '1.5' }}>
                {t('completeInfoForCompliance', { ns: 'settings', defaultValue: 'Complete business information is required for regulatory compliance and to enable financial transactions.' })}
              </p>
            </div>
          </div>
        </div>

        {/* Required Fields Section */}
        <div
          style={{
            backgroundColor: 'var(--bg-tertiary)',
            borderRadius: '12px',
            padding: '24px',
            marginBottom: '32px',
            border: '1px solid var(--border-primary)'
          }}
        >
          <h3
            style={{
              fontSize: '18px',
              fontWeight: '600',
              color: 'var(--text-primary)',
              marginBottom: '20px',
              display: 'flex',
              alignItems: 'center',
              gap: '8px'
            }}
          >
            <span className="material-symbols-outlined" style={{ fontSize: '22px', color: 'var(--accent)' }}>
              checklist
            </span>
            {t('requiredFields', { ns: 'settings', defaultValue: 'Required Fields' })}
          </h3>
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
              gap: '12px'
            }}
          >
            {[
              { key: 'tradingName', icon: 'business', label: t('tradingName', { ns: 'settings', defaultValue: 'Trading Name' }) },
              { key: 'registrationType', icon: 'description', label: t('registrationType', { ns: 'settings', defaultValue: 'Registration Type' }) },
              { key: 'industry', icon: 'work', label: t('industry', { ns: 'settings', defaultValue: 'Industry' }) },
              { key: 'dateOfIncorporation', icon: 'event', label: t('dateOfIncorporation', { ns: 'settings', defaultValue: 'Date of Incorporation' }) },
              { key: 'registrationNumber', icon: 'badge', label: t('registrationNumber', { ns: 'settings', defaultValue: 'Registration Number' }) },
              { key: 'tinNumber', icon: 'receipt_long', label: t('tinNumber', { ns: 'settings', defaultValue: 'TIN Number' }) },
              { key: 'businessEmail', icon: 'email', label: t('businessEmail', { ns: 'settings', defaultValue: 'Business Email' }) },
              { key: 'businessPhone', icon: 'phone', label: t('businessPhone', { ns: 'settings', defaultValue: 'Business Phone' }) },
              { key: 'gpsAddress', icon: 'location_on', label: t('gpsAddress', { ns: 'settings', defaultValue: 'GPS Address' }) }
            ].map((field) => (
              <div
                key={field.key}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '10px',
                  fontSize: '14px',
                  color: 'var(--text-primary)',
                  padding: '10px',
                  backgroundColor: 'var(--bg-primary)',
                  borderRadius: '8px',
                  border: '1px solid var(--border-primary)'
                }}
              >
                <span
                  className="material-symbols-outlined"
                  style={{
                    fontSize: '20px',
                    color: 'var(--accent)',
                    flexShrink: 0
                  }}
                >
                  {field.icon}
                </span>
                <span style={{ fontWeight: '500' }}>{field.label}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Action Buttons */}
        <div
          style={{
            display: 'flex',
            gap: '12px',
            flexDirection: 'column'
          }}
        >
          <button
            onClick={handleGoToBusinessSettings}
            style={{
              padding: '16px 24px',
              backgroundColor: 'var(--accent)',
              color: 'var(--text-inverse)',
              border: 'none',
              borderRadius: '10px',
              fontSize: '16px',
              fontWeight: '600',
              cursor: 'pointer',
              transition: 'all 0.2s ease',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '10px',
              boxShadow: '0 4px 12px rgba(0, 0, 0, 0.15)'
            }}
            onMouseOver={(e) => {
              e.target.style.backgroundColor = 'var(--accent-hover, var(--accent))';
              e.target.style.transform = 'translateY(-2px)';
              e.target.style.boxShadow = '0 6px 16px rgba(0, 0, 0, 0.2)';
            }}
            onMouseOut={(e) => {
              e.target.style.backgroundColor = 'var(--accent)';
              e.target.style.transform = 'translateY(0)';
              e.target.style.boxShadow = '0 4px 12px rgba(0, 0, 0, 0.15)';
            }}
          >
            <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>
              settings
            </span>
            {t('completeBusinessInfo', { ns: 'settings', defaultValue: 'Complete Business Information' })}
          </button>
          <button
            onClick={onClose}
            style={{
              padding: '12px 24px',
              backgroundColor: 'transparent',
              color: 'var(--text-secondary)',
              border: '1px solid var(--border-primary)',
              borderRadius: '10px',
              fontSize: '15px',
              fontWeight: '500',
              cursor: 'pointer',
              transition: 'all 0.2s ease'
            }}
            onMouseOver={(e) => {
              e.target.style.backgroundColor = 'var(--bg-secondary)';
              e.target.style.color = 'var(--text-primary)';
            }}
            onMouseOut={(e) => {
              e.target.style.backgroundColor = 'transparent';
              e.target.style.color = 'var(--text-secondary)';
            }}
          >
            {t('cancel', { ns: 'settings', defaultValue: 'Cancel' })}
          </button>
        </div>
      </div>
    </div>
  );

  return createPortal(modalContent, document.body);
};

export default BusinessInfoRequiredModal;
