/**
 * Business Verification Settings Page
 * 
 * Manages KYC verification process for business users. Displays verification
 * levels, handles business document uploads (COI, BRC, Ghana Card, etc.),
 * email and phone verification, and tracks document verification status
 * through multiple verification stages.
 */

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { kycService, profileService } from '@/features/settings/services';
import { authService, tokenService } from '@/features/auth/services';
import { useVerificationLevel } from '@/features/settings/hooks/useVerificationLevel.js';
import { useEmailPhoneVerification } from '@/features/settings/hooks/useEmailPhoneVerification.js';
import { logger } from '@/shared/utils/logger.js';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { checkBusinessInfoComplete } from '@/features/settings/utils/businessInfoChecker.js';
import LockedVerificationLevel from '@/features/settings/components/verification/LockedVerificationLevel.jsx';
import BusinessInfoRequiredModal from '@/features/settings/components/verification/BusinessInfoRequiredModal.jsx';
import { useIsMounted } from '@/shared/hooks/useIsMounted.js';
import VerificationProgressGuide from '@/features/settings/components/verification/VerificationProgressGuide.jsx';
import VerificationNextSteps from '@/features/settings/components/verification/VerificationNextSteps.jsx';

const Verification = () => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const isMounted = useIsMounted();
  const [verificationStatus, setVerificationStatus] = useState({
    level0: { completed: true, documents: { email: true, phone: true } },
    level1: { completed: false, documents: { emailVerified: false, phoneVerified: false } },
    level2: { completed: false, documents: { coiDoc: false, ghanaCardFront: false, ghanaCardBack: false, brcDoc: false } },
    level3: { completed: false, documents: { blDoc: false, opDoc: false, proofOfAddress: false } }
  });

  const [uploadedFiles, setUploadedFiles] = useState({
    coiDoc: false,
    ghanaCardFront: false,
    ghanaCardBack: false,
    brcDoc: false,
    blDoc: false,
    opDoc: false,
    proofOfAddress: false
  });

  const [documentVerificationStatus, setDocumentVerificationStatus] = useState({
    coiDoc: null,
    ghanaCardFront: null,
    ghanaCardBack: null,
    brcDoc: null,
    blDoc: null,
    opDoc: null,
    proofOfAddress: null
  });

  const [businessId, setBusinessId] = useState(null);
  const [showBusinessInfoModal, setShowBusinessInfoModal] = useState(false);
  const [lockedLevel, setLockedLevel] = useState(null);
  const [isBusinessInfoComplete, setIsBusinessInfoComplete] = useState(false);
  const [isCheckingBusinessInfo, setIsCheckingBusinessInfo] = useState(false);
  const [isInitialLoading, setIsInitialLoading] = useState(true);
  const lastCheckedBusinessIdRef = useRef(null);
  const isMobile = typeof window !== 'undefined' ? window.innerWidth <= 768 : false;

  // Use custom hooks - moved to top to fix temporal dead zone
  const { verificationLevel: apiVerificationLevel, isLoading: isVerificationLevelLoading } = useVerificationLevel();
  const {
    phoneOtp, setPhoneOtp, emailToken, setEmailToken, showPhoneOtpInput, setShowPhoneOtpInput,
    showEmailTokenInput, setShowEmailTokenInput, isVerifyingPhone, isVerifyingEmail,
    isRequestingEmailVerification, requestEmailVerification, verifyEmail, requestPhoneVerification,
    verifyPhone, fetchVerificationStatus,
  } = useEmailPhoneVerification();

  const normalizeDocumentStatus = (status) => {
    if (status === true || status === false || status === null || status === undefined) {
      return status;
    }
    const normalized = String(status).toUpperCase();
    if (['VERIFIED', 'APPROVED', 'ACCEPTED'].includes(normalized)) {
      return true;
    }
    if (normalized === 'PENDING') {
      return false;
    }
    if (['REJECTED', 'DECLINED', 'FAILED'].includes(normalized)) {
      return 'rejected';
    }
    return status;
  };

  const resolveDocumentStatus = (currentStatus, nextStatus) => {
    if (nextStatus === true) {
      return true;
    }
    if (nextStatus === false) {
      return false;
    }
    if (currentStatus === true) {
      return true;
    }
    if (currentStatus === false) {
      return false;
    }
    if (currentStatus === 'rejected') {
      return currentStatus;
    }
    return nextStatus;
  };

  // Handle unlock click - show modal
  const handleUnlockClick = (level) => {
    setLockedLevel(level);
    setShowBusinessInfoModal(true);
  };

  // Load persisted verification status from localStorage on mount
  useEffect(() => {
    try {
      const persisted = localStorage.getItem('businessVerificationStatus');
      if (persisted) {
        const parsed = JSON.parse(persisted);
        setDocumentVerificationStatus(prev => ({ ...prev, ...parsed }));
        setUploadedFiles(prev => {
          const persistedUploaded = localStorage.getItem('businessUploadedFiles');
          if (persistedUploaded) {
            return { ...prev, ...JSON.parse(persistedUploaded) };
          }
          return prev;
        });
      }
    } catch (e) {
      logger.warn('Failed to load persisted verification status', { error: e });
    }
  }, []);

  // Persist verification status to localStorage whenever it changes
  useEffect(() => {
    try {
      localStorage.setItem('businessVerificationStatus', JSON.stringify(documentVerificationStatus));
      localStorage.setItem('businessUploadedFiles', JSON.stringify(uploadedFiles));
    } catch (e) {
      logger.warn('Failed to persist verification status', { error: e });
    }
  }, [documentVerificationStatus, uploadedFiles]);

  // Manage initial loading state - wait for all data to load
  useEffect(() => {
    const allDataLoaded = !isVerificationLevelLoading && !isCheckingBusinessInfo;
    if (allDataLoaded) {
      // Add a small delay to ensure smooth transition
      const timer = setTimeout(() => {
        setIsInitialLoading(false);
      }, 300);
      return () => clearTimeout(timer);
    }
  }, [isVerificationLevelLoading, isCheckingBusinessInfo]);



  // Check business info when businessId is available
  useEffect(() => {
    if (!businessId) {
      setIsBusinessInfoComplete(false);
      setIsCheckingBusinessInfo(false);
      lastCheckedBusinessIdRef.current = null;
      return;
    }

    // Skip if we already checked this businessId
    if (lastCheckedBusinessIdRef.current === businessId) {
      return;
    }

    let cancelled = false;

    const verifyBusinessInfo = async () => {
      try {
        if (isMounted()) {
          setIsCheckingBusinessInfo(true);
        }
        const { isComplete, missingFields } = await checkBusinessInfoComplete(businessId);

        if (cancelled || !isMounted()) { return; }

        lastCheckedBusinessIdRef.current = businessId;
        setIsBusinessInfoComplete(isComplete);
        if (!isComplete && missingFields.length > 0) {
          logger.debug('Missing business info fields', { missingFields: missingFields.map(f => f.key) });
        }
      } catch (error) {
        if (cancelled || !isMounted()) { return; }
        logger.error('Failed to verify business info', { error });
        setIsBusinessInfoComplete(false);
      } finally {
        if (!cancelled && isMounted()) {
          setIsCheckingBusinessInfo(false);
        }
      }
    };

    verifyBusinessInfo();

    return () => {
      cancelled = true;
    };
    // Only depend on businessId - isMounted is stable and doesn't need to be in deps
  }, [businessId]);

  // Refresh business info check when page becomes visible (user returns from settings)
  useEffect(() => {
    if (!businessId) { return; }

    let cancelled = false;

    const handleVisibilityChange = () => {
      if (!document.hidden && businessId && !cancelled) {
        checkBusinessInfoComplete(businessId).then(({ isComplete }) => {
          if (!cancelled && isMounted()) {
            setIsBusinessInfoComplete(isComplete);
          }
        }).catch((error) => {
          if (!cancelled && isMounted()) {
            logger.error('Failed to verify business info on visibility change', { error });
          }
        });
      }
    };

    const handleFocus = () => {
      if (businessId && !cancelled) {
        checkBusinessInfoComplete(businessId).then(({ isComplete }) => {
          if (!cancelled && isMounted()) {
            setIsBusinessInfoComplete(isComplete);
          }
        }).catch((error) => {
          if (!cancelled && isMounted()) {
            logger.error('Failed to verify business info on focus', { error });
          }
        });
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);
    window.addEventListener('focus', handleFocus);

    return () => {
      cancelled = true;
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      window.removeEventListener('focus', handleFocus);
    };
    // Only depend on businessId - isMounted is stable and doesn't need to be in deps
  }, [businessId]);

  // Use React Query mutation for business document uploads with automatic cache invalidation
  const uploadDocumentMutation = useMutation({
    mutationFn: async ({ businessId, formData, documentType }) => {
      // For Ghana Card, use the individual upload endpoint (same as individual verification)
      if (documentType === 'ghanaCardFront' || documentType === 'ghanaCardBack') {
        return await kycService.uploadKYCDocument(formData);
      }
      // For other documents, use business upload endpoint
      return await kycService.uploadBusinessKYCDocument(businessId, formData);
    },
    invalidateQueries: [
      queryKeys.settings.verification(),
      queryKeys.settings.verificationLevel('business_contact', businessId),
      queryKeys.settings.all(),
    ],
    onSuccess: async (response, variables) => {
      const { documentType, part } = variables;

      // Update local state
      const docKey = documentType;
      const levelKey = documentType === 'coiDoc' || documentType === 'ghanaCardFront' || documentType === 'ghanaCardBack' || documentType === 'brcDoc' ? 'level2' : 'level3';

      setUploadedFiles(prev => ({
        ...prev,
        [docKey]: true
      }));

      setVerificationStatus(prev => ({
        ...prev,
        [levelKey]: {
          ...prev[levelKey],
          documents: {
            ...prev[levelKey].documents,
            [docKey]: true
          }
        }
      }));

      setDocumentVerificationStatus(prev => ({
        ...prev,
        [docKey]: false // false means uploaded but pending verification
      }));

      // Refetch both business and individual KYC documents to get updated status
      try {
        const [businessKycResponse, individualKycResponse] = await Promise.allSettled([
          kycService.getBusinessKYCDocuments(businessId),
          kycService.getKYCDocuments() // Fetch individual endpoint for Ghana Card
        ]);

        logger.debug('Business KYC Response after upload', { response: businessKycResponse });
        logger.debug('Individual KYC Response after upload (for Ghana Card)', { response: individualKycResponse });

        const businessDocuments = businessKycResponse.status === 'fulfilled'
          ? (Array.isArray(businessKycResponse.value)
            ? businessKycResponse.value
            : (businessKycResponse.value?.data || []))
          : [];

        const individualDocuments = individualKycResponse.status === 'fulfilled'
          ? (Array.isArray(individualKycResponse.value)
            ? individualKycResponse.value
            : (individualKycResponse.value?.data || []))
          : [];

        if (Array.isArray(businessDocuments) || Array.isArray(individualDocuments)) {
          const verificationStatusMap = {};

          // Process individual documents first (for Ghana Card) - these take priority
          individualDocuments.forEach(doc => {
            if (doc.document_type === 'GHANA_CARD') {
              const hasFront = !!doc.document_front_url;
              const hasBack = !!doc.document_back_url;
              const statusUpper = (doc.status || '').toUpperCase();
              const isVerified = (hasFront || hasBack) && (
                statusUpper === 'VERIFIED' ||
                statusUpper === 'APPROVED' ||
                statusUpper === 'ACCEPTED'
              );
              const isPending = (hasFront || hasBack) && statusUpper === 'PENDING';
              const isRejected = (hasFront || hasBack) && (
                statusUpper === 'REJECTED' ||
                statusUpper === 'DECLINED' ||
                statusUpper === 'FAILED'
              );

              // Status: true = verified, false = pending, 'rejected' = rejected, null = not uploaded
              if (hasFront) { verificationStatusMap.ghanaCardFront = isVerified ? true : (isRejected ? 'rejected' : (isPending ? false : null)); }
              if (hasBack) { verificationStatusMap.ghanaCardBack = isVerified ? true : (isRejected ? 'rejected' : (isPending ? false : null)); }
            }
          });

          // Process business documents (excluding Ghana Card if already found in individual endpoint)
          businessDocuments.forEach(doc => {
            // Skip Ghana Card if already processed from individual endpoint
            if (doc.doc_type === 'GHANA_CARD_FRONT' || doc.doc_type === 'GHANA_CARD_BACK') {
              // Only use business endpoint Ghana Card if individual endpoint doesn't have it
              if (doc.doc_type === 'GHANA_CARD_FRONT' && verificationStatusMap.ghanaCardFront === undefined) {
                const isUploaded = !!doc.file_url;
                const statusUpper = (doc.status || '').toUpperCase();
                const isVerified = isUploaded && (
                  statusUpper === 'VERIFIED' ||
                  statusUpper === 'APPROVED' ||
                  statusUpper === 'ACCEPTED'
                );
                const isPending = isUploaded && statusUpper === 'PENDING';
                const isRejected = isUploaded && (
                  statusUpper === 'REJECTED' ||
                  statusUpper === 'DECLINED' ||
                  statusUpper === 'FAILED'
                );
                verificationStatusMap.ghanaCardFront = isVerified ? true : (isRejected ? 'rejected' : (isPending ? false : null));
              }
              if (doc.doc_type === 'GHANA_CARD_BACK' && verificationStatusMap.ghanaCardBack === undefined) {
                const isUploaded = !!doc.file_url;
                const statusUpper = (doc.status || '').toUpperCase();
                const isVerified = isUploaded && (
                  statusUpper === 'VERIFIED' ||
                  statusUpper === 'APPROVED' ||
                  statusUpper === 'ACCEPTED'
                );
                const isPending = isUploaded && statusUpper === 'PENDING';
                const isRejected = isUploaded && (
                  statusUpper === 'REJECTED' ||
                  statusUpper === 'DECLINED' ||
                  statusUpper === 'FAILED'
                );
                verificationStatusMap.ghanaCardBack = isVerified ? true : (isRejected ? 'rejected' : (isPending ? false : null));
              }
              return;
            }

            // Map other business document types
            const hasFile = !!doc.file_url;
            const statusUpper = (doc.status || '').toUpperCase();
            const isVerified = hasFile && (
              statusUpper === 'VERIFIED' ||
              statusUpper === 'APPROVED' ||
              statusUpper === 'ACCEPTED'
            );
            const isPending = hasFile && statusUpper === 'PENDING';
            const isRejected = hasFile && (
              statusUpper === 'REJECTED' ||
              statusUpper === 'DECLINED' ||
              statusUpper === 'FAILED'
            );

            const nextStatus = isVerified ? true : (isRejected ? 'rejected' : (isPending ? false : null));
            // Status: true = verified, false = pending, 'rejected' = rejected, null = not uploaded
            if (doc.doc_type === 'COI_DOC') {
              verificationStatusMap.coiDoc = resolveDocumentStatus(verificationStatusMap.coiDoc, nextStatus);
            } else if (doc.doc_type === 'BRC_DOC') {
              verificationStatusMap.brcDoc = resolveDocumentStatus(verificationStatusMap.brcDoc, nextStatus);
            } else if (doc.doc_type === 'BL_DOC') {
              verificationStatusMap.blDoc = resolveDocumentStatus(verificationStatusMap.blDoc, nextStatus);
            } else if (doc.doc_type === 'OP_DOC') {
              verificationStatusMap.opDoc = resolveDocumentStatus(verificationStatusMap.opDoc, nextStatus);
            } else if (doc.doc_type === 'PROOF_OF_ADDRESS') {
              verificationStatusMap.proofOfAddress = resolveDocumentStatus(verificationStatusMap.proofOfAddress, nextStatus);
            }
          });

          setDocumentVerificationStatus(prev => ({
            ...prev,
            ...verificationStatusMap
          }));

          const uploadedStatusFromMap = {
            coiDoc: verificationStatusMap.coiDoc !== null && verificationStatusMap.coiDoc !== undefined,
            ghanaCardFront: verificationStatusMap.ghanaCardFront !== null && verificationStatusMap.ghanaCardFront !== undefined,
            ghanaCardBack: verificationStatusMap.ghanaCardBack !== null && verificationStatusMap.ghanaCardBack !== undefined,
            brcDoc: verificationStatusMap.brcDoc !== null && verificationStatusMap.brcDoc !== undefined,
            blDoc: verificationStatusMap.blDoc !== null && verificationStatusMap.blDoc !== undefined,
            opDoc: verificationStatusMap.opDoc !== null && verificationStatusMap.opDoc !== undefined,
            proofOfAddress: verificationStatusMap.proofOfAddress !== null && verificationStatusMap.proofOfAddress !== undefined,
          };

          setUploadedFiles(prev => ({
            ...prev,
            ...uploadedStatusFromMap
          }));
        }
      } catch (refreshError) {
        logger.error('Failed to refresh business KYC documents after upload', { error: refreshError });
      }

      success(t('documentUploadedSuccessfully', {
        ns: 'settings',
        defaultValue: '✓ Document uploaded! We will review it shortly.'
      }));
    },
    onError: (error) => {
      // Check for specific error types and show user-friendly messages
      const errorMessage = error?.message || '';
      if (errorMessage.toLowerCase().includes('413') || errorMessage.toLowerCase().includes('too large')) {
        showError(t('fileSizeExceeds10MB', { ns: 'settings', defaultValue: 'File is too large (max 10MB). Please compress it and try again.' }));
      } else if (errorMessage.toLowerCase().includes('file type') || errorMessage.toLowerCase().includes('format')) {
        showError(t('invalidFileType', { ns: 'settings', defaultValue: 'Invalid format. Please upload a JPG, PNG, or PDF file.' }));
      } else {
        showError(t('errorUploadingDocument', { ns: 'settings', defaultValue: 'Upload failed. Please check your connection and try again.' }));
      }
    },
  });

  useEffect(() => {
    const loadBusinessData = async () => {
      try {
        const userData = JSON.parse(localStorage.getItem('userData') || '{}');
        const id = userData?.businesses?.[0]?.id || userData?.business?.id;
        if (!id) {
          showError(t('businessIdNotFound', { ns: 'settings', defaultValue: 'Business account not found. Please refresh the page.' }));
          return;
        }
        setBusinessId(id);

        // Use verification level from hook
        const verificationLevel = apiVerificationLevel || 0;

        // Attempt to get fine-grained email/phone verification status from dedicated endpoint
        try {
          const check = await fetchVerificationStatus();
          const payload = check || {};

          const emailVerifiedRaw = payload?.emailVerified ?? payload?.email_verified ?? payload?.data?.emailVerified ?? payload?.data?.email_verified;
          const phoneVerifiedRaw = payload?.phoneVerified ?? payload?.phone_verified ?? payload?.data?.phoneVerified ?? payload?.data?.phone_verified;
          const emailPendingRaw = payload?.emailPending ?? payload?.email_pending ?? payload?.data?.emailPending ?? payload?.data?.email_pending;
          const phonePendingRaw = payload?.phonePending ?? payload?.phone_pending ?? payload?.data?.phonePending ?? payload?.data?.phone_pending;

          const mapStatus = (verified, pending) => {
            if (verified === true || String(verified).toLowerCase() === 'true') { return true; }
            if (pending === true || String(pending).toLowerCase() === 'true') { return 'PENDING'; }
            return false;
          };

          const emailStatus = mapStatus(emailVerifiedRaw, emailPendingRaw);
          const phoneStatus = mapStatus(phoneVerifiedRaw, phonePendingRaw);

          setVerificationStatus(prev => ({
            ...prev,
            level1: {
              ...prev.level1,
              documents: {
                emailVerified: emailStatus,
                phoneVerified: phoneStatus
              }
            }
          }));
        } catch (checkErr) {
          logger.warn('Could not load email/phone check endpoint, falling back to profile', { error: checkErr });
          // Only load profile data if endpoint fails
          try {
            const profileResponse = await profileService.getUserProfile();
            const profileData = profileResponse?.data || profileResponse;
            const isEmailVerified = profileData?.is_email_verified || profileData?.user?.is_email_verified || false;
            const isPhoneVerified = profileData?.is_phone_verified || profileData?.user?.is_phone_verified || false;

            setVerificationStatus(prev => ({
              ...prev,
              level1: {
                ...prev.level1,
                documents: {
                  emailVerified: isEmailVerified,
                  phoneVerified: isPhoneVerified
                }
              }
            }));
          } catch (profileError) {
            logger.warn('Could not load email/phone verification status', { error: profileError });
            // Non-critical, continue with rest of the loading
          }
        }

        // Fetch both business KYC documents and individual KYC documents (for Ghana Card)
        const [businessKycResponse, individualKycResponse] = await Promise.allSettled([
          kycService.getBusinessKYCDocuments(id),
          kycService.getKYCDocuments() // Fetch individual endpoint for Ghana Card
        ]);

        logger.debug('Business KYC Response', { response: businessKycResponse });
        logger.debug('Individual KYC Response (for Ghana Card)', { response: individualKycResponse });

        // Handle business documents response
        const businessDocuments = businessKycResponse.status === 'fulfilled'
          ? (Array.isArray(businessKycResponse.value)
            ? businessKycResponse.value
            : (businessKycResponse.value?.data || []))
          : [];

        // Handle individual documents response (for Ghana Card)
        const individualDocuments = individualKycResponse.status === 'fulfilled'
          ? (Array.isArray(individualKycResponse.value)
            ? individualKycResponse.value
            : (individualKycResponse.value?.data || []))
          : [];

        // Update upload status and verification status based on existing documents
        const uploadedStatus = {};
        const verificationStatusMap = {};

        // Process individual documents first (for Ghana Card) - these take priority
        individualDocuments.forEach(doc => {
          logger.debug('Processing individual doc for Ghana Card', {
            document_type: doc.document_type,
            status: doc.status,
            hasFront: !!doc.document_front_url,
            hasBack: !!doc.document_back_url
          });

          if (doc.document_type === 'GHANA_CARD') {
            const hasFront = !!doc.document_front_url;
            const hasBack = !!doc.document_back_url;
            const statusUpper = (doc.status || '').toUpperCase();
            const isVerified = (hasFront || hasBack) && (
              statusUpper === 'VERIFIED' ||
              statusUpper === 'APPROVED' ||
              statusUpper === 'ACCEPTED'
            );
            const isPending = (hasFront || hasBack) && statusUpper === 'PENDING';
            const isRejected = (hasFront || hasBack) && (
              statusUpper === 'REJECTED' ||
              statusUpper === 'DECLINED' ||
              statusUpper === 'FAILED'
            );

            // Status: true = verified, false = pending, 'rejected' = rejected, null = not uploaded
            const nextStatus = isVerified ? true : (isRejected ? 'rejected' : (isPending ? false : null));
            if (hasFront) {
              uploadedStatus.ghanaCardFront = true;
              verificationStatusMap.ghanaCardFront = resolveDocumentStatus(verificationStatusMap.ghanaCardFront, nextStatus);
            }
            if (hasBack) {
              uploadedStatus.ghanaCardBack = true;
              verificationStatusMap.ghanaCardBack = resolveDocumentStatus(verificationStatusMap.ghanaCardBack, nextStatus);
            }
          }
        });

        // Process business documents (excluding Ghana Card if already found in individual endpoint)
        businessDocuments.forEach(doc => {
          logger.debug('Processing business doc', {
            doc_type: doc.doc_type,
            status: doc.status,
            hasFile: !!doc.file_url
          });

          // Skip Ghana Card documents if we already have them from individual endpoint
          if (doc.doc_type === 'GHANA_CARD_FRONT' || doc.doc_type === 'GHANA_CARD_BACK') {
            // Only use business endpoint Ghana Card if individual endpoint doesn't have it
            if (doc.doc_type === 'GHANA_CARD_FRONT' && !uploadedStatus.ghanaCardFront) {
              const isUploaded = !!doc.file_url;
              const statusUpper = (doc.status || '').toUpperCase();
              const isVerified = isUploaded && (
                statusUpper === 'VERIFIED' ||
                statusUpper === 'APPROVED' ||
                statusUpper === 'ACCEPTED'
              );
              const isPending = isUploaded && statusUpper === 'PENDING';
              const isRejected = isUploaded && (
                statusUpper === 'REJECTED' ||
                statusUpper === 'DECLINED' ||
                statusUpper === 'FAILED'
              );
              const nextStatus = isVerified ? true : (isRejected ? 'rejected' : (isPending ? false : null));
              uploadedStatus.ghanaCardFront = isUploaded;
              verificationStatusMap.ghanaCardFront = resolveDocumentStatus(verificationStatusMap.ghanaCardFront, nextStatus);
            }
            if (doc.doc_type === 'GHANA_CARD_BACK' && !uploadedStatus.ghanaCardBack) {
              const isUploaded = !!doc.file_url;
              const statusUpper = (doc.status || '').toUpperCase();
              const isVerified = isUploaded && (
                statusUpper === 'VERIFIED' ||
                statusUpper === 'APPROVED' ||
                statusUpper === 'ACCEPTED'
              );
              const isPending = isUploaded && statusUpper === 'PENDING';
              const isRejected = isUploaded && (
                statusUpper === 'REJECTED' ||
                statusUpper === 'DECLINED' ||
                statusUpper === 'FAILED'
              );
              const nextStatus = isVerified ? true : (isRejected ? 'rejected' : (isPending ? false : null));
              uploadedStatus.ghanaCardBack = isUploaded;
              verificationStatusMap.ghanaCardBack = resolveDocumentStatus(verificationStatusMap.ghanaCardBack, nextStatus);
            }
            return; // Skip processing if already handled
          }

          // Process other business documents
          const isUploaded = !!doc.file_url;
          const statusUpper = (doc.status || '').toUpperCase();
          const isVerified = isUploaded && (
            statusUpper === 'VERIFIED' ||
            statusUpper === 'APPROVED' ||
            statusUpper === 'ACCEPTED'
          );
          const isPending = isUploaded && statusUpper === 'PENDING';
          const isRejected = isUploaded && (
            statusUpper === 'REJECTED' ||
            statusUpper === 'DECLINED' ||
            statusUpper === 'FAILED'
          );

          // Status: true = verified, false = pending, 'rejected' = rejected, null = not uploaded
          // Map document types to state keys
          const nextStatus = isVerified ? true : (isRejected ? 'rejected' : (isPending ? false : null));
          if (doc.doc_type === 'COI_DOC') {
            uploadedStatus.coiDoc = isUploaded;
            verificationStatusMap.coiDoc = resolveDocumentStatus(verificationStatusMap.coiDoc, nextStatus);
          }
          if (doc.doc_type === 'BRC_DOC') {
            uploadedStatus.brcDoc = isUploaded;
            verificationStatusMap.brcDoc = resolveDocumentStatus(verificationStatusMap.brcDoc, nextStatus);
          }
          if (doc.doc_type === 'BL_DOC') {
            uploadedStatus.blDoc = isUploaded;
            verificationStatusMap.blDoc = resolveDocumentStatus(verificationStatusMap.blDoc, nextStatus);
          }
          if (doc.doc_type === 'OP_DOC') {
            uploadedStatus.opDoc = isUploaded;
            verificationStatusMap.opDoc = resolveDocumentStatus(verificationStatusMap.opDoc, nextStatus);
          }
          if (doc.doc_type === 'PROOF_OF_ADDRESS') {
            uploadedStatus.proofOfAddress = isUploaded;
            verificationStatusMap.proofOfAddress = resolveDocumentStatus(verificationStatusMap.proofOfAddress, nextStatus);
          }
        });

        // Update verification status for uploaded documents
        // Levels should only be completed when business info is complete AND all required documents are verified
        const allLevel2Verified = isBusinessInfoComplete &&
          (verificationStatusMap.ghanaCardFront === true && verificationStatusMap.ghanaCardBack === true) &&
          (verificationStatusMap.coiDoc === true || !uploadedStatus.coiDoc) &&
          (verificationStatusMap.brcDoc === true || !uploadedStatus.brcDoc);

        const allLevel3Verified = isBusinessInfoComplete &&
          (verificationStatusMap.blDoc === true) &&
          (verificationStatusMap.opDoc === true) &&
          (verificationStatusMap.proofOfAddress === true);

        setVerificationStatus(prev => ({
          ...prev,
          level1: {
            ...prev.level1,
            completed: verificationLevel >= 1 || (prev.level1.documents.emailVerified === true && prev.level1.documents.phoneVerified === true)
          },
          level2: {
            ...prev.level2,
            completed: isBusinessInfoComplete && (verificationLevel >= 2 || allLevel2Verified), // Require business info completion
            documents: {
              coiDoc: uploadedStatus.coiDoc || false,
              ghanaCardFront: uploadedStatus.ghanaCardFront || false,
              ghanaCardBack: uploadedStatus.ghanaCardBack || false,
              brcDoc: uploadedStatus.brcDoc || false
            }
          },
          level3: {
            ...prev.level3,
            completed: isBusinessInfoComplete && (verificationLevel >= 3 || allLevel3Verified), // Require business info completion
            documents: {
              blDoc: uploadedStatus.blDoc || false,
              opDoc: uploadedStatus.opDoc || false,
              proofOfAddress: uploadedStatus.proofOfAddress || false
            }
          }
        }));

        // Update uploadedFiles state based on server response
        setUploadedFiles({
          coiDoc: uploadedStatus.coiDoc || false,
          ghanaCardFront: uploadedStatus.ghanaCardFront || false,
          ghanaCardBack: uploadedStatus.ghanaCardBack || false,
          brcDoc: uploadedStatus.brcDoc || false,
          blDoc: uploadedStatus.blDoc || false,
          opDoc: uploadedStatus.opDoc || false,
          proofOfAddress: uploadedStatus.proofOfAddress || false
        });

        // Update document verification status
        setDocumentVerificationStatus(prev => ({
          ...prev,
          ...verificationStatusMap
        }));

        logger.debug('Updated verification status', { verificationStatusMap });
      } catch (error) {
        logger.error('Failed to load business data', { error });
        // Don't show error to user for background data loading
      }
    };

    if (apiVerificationLevel !== undefined) {
      loadBusinessData();
    }
  }, [apiVerificationLevel, showError, t]);

  const handleFileUpload = async (documentType, part, file) => {
    if (!file) { return; }
    if (!businessId) {
      showError(t('businessIdNotFound', { ns: 'settings', defaultValue: 'Unable to upload. Please refresh the page and try again.' }));
      return;
    }

    // Validate file size (10MB limit)
    const maxSize = 10 * 1024 * 1024; // 10MB in bytes
    if (file.size > maxSize) {
      showError(t('fileSizeExceeds10MB', { ns: 'settings', defaultValue: 'File is too large (max 10MB). Please compress it and try again.' }));
      return;
    }

    // Validate file type
    const allowedTypes = ['image/jpeg', 'image/jpg', 'image/png', 'application/pdf'];
    if (!allowedTypes.includes(file.type)) {
      showError(t('invalidFileType', { ns: 'settings', defaultValue: 'Invalid format. Please upload a JPG, PNG, or PDF file.' }));
      return;
    }

    // For Ghana Card, use the same endpoint as individual verification
    if (documentType === 'ghanaCardFront' || documentType === 'ghanaCardBack') {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('document_type', 'GHANA_CARD');
      formData.append('part', documentType === 'ghanaCardFront' ? 'front' : 'back');
      formData.append('usertype', 'business_contact'); // Use business_contact for business users

      // Use individual upload endpoint for Ghana Card
      uploadDocumentMutation.mutate({ businessId, formData, documentType, part });
      return;
    }

    // Map other document types to API format (non-Ghana Card documents)
    const documentTypeMapping = {
      coiDoc: 'COI_DOC',
      brcDoc: 'BRC_DOC',
      blDoc: 'BL_DOC',
      opDoc: 'OP_DOC',
      proofOfAddress: 'PROOF_OF_ADDRESS'
    };

    const apiDocumentType = documentTypeMapping[documentType] || documentType;

    const formData = new FormData();
    formData.append('doc_type', apiDocumentType);
    formData.append('file', file);

    // Execute mutation - onSuccess and onError are handled in mutation config
    uploadDocumentMutation.mutate({ businessId, formData, documentType, part });
  };

  const handleEmailVerification = async () => {
    if (emailToken.trim()) {
      const verified = await verifyEmail();
      if (verified) {
        setVerificationStatus(prev => ({
          ...prev,
          level1: {
            ...prev.level1,
            documents: {
              ...prev.level1.documents,
              emailVerified: true
            }
          }
        }));
        // Refetch verification status to ensure backend state is reflected
        try {
          const check = await fetchVerificationStatus();
          if (check) {
            const emailVerifiedRaw = check?.emailVerified ?? check?.email_verified ?? check?.data?.emailVerified ?? check?.data?.email_verified;
            if (emailVerifiedRaw === true || String(emailVerifiedRaw).toLowerCase() === 'true') {
              setVerificationStatus(prev => ({
                ...prev,
                level1: {
                  ...prev.level1,
                  documents: {
                    ...prev.level1.documents,
                    emailVerified: true
                  }
                }
              }));
            }
          }
        } catch (error) {
          logger.warn('Failed to refetch verification status after email verification', { error });
        }
      }
    } else {
      setShowEmailTokenInput(true);
    }
  };

  const handleRequestEmailVerification = requestEmailVerification;

  const handlePhoneVerification = async () => {
    if (phoneOtp.trim()) {
      const verified = await verifyPhone();
      if (verified) {
        setVerificationStatus(prev => ({
          ...prev,
          level1: {
            ...prev.level1,
            documents: {
              ...prev.level1.documents,
              phoneVerified: true
            }
          }
        }));
        // Refetch verification status to ensure backend state is reflected
        try {
          const check = await fetchVerificationStatus();
          if (check) {
            const phoneVerifiedRaw = check?.phoneVerified ?? check?.phone_verified ?? check?.data?.phoneVerified ?? check?.data?.phone_verified;
            if (phoneVerifiedRaw === true || String(phoneVerifiedRaw).toLowerCase() === 'true') {
              setVerificationStatus(prev => ({
                ...prev,
                level1: {
                  ...prev.level1,
                  documents: {
                    ...prev.level1.documents,
                    phoneVerified: true
                  }
                }
              }));
            }
          }
        } catch (error) {
          logger.warn('Failed to refetch verification status after phone verification', { error });
        }
      }
    } else {
      // Request OTP first
      try {
        const response = await authService.requestVerifyPhoneOtp();
        if (response.code === '00') {
          success(t('otpSentToPhone', { ns: 'settings', defaultValue: '✓ OTP sent! Please check your phone.' }));
          setShowPhoneOtpInput(true);
        } else {
          showError(t('pleaseTryAgain', { ns: 'settings', defaultValue: 'Please try again.' }));
        }
      } catch (error) {
        logger.error('Failed to request phone OTP', { error });
        showError(t('pleaseTryAgain', { ns: 'settings', defaultValue: 'Please try again.' }));
      }
    }
  };

  // Ensure level 0 is always marked as completed (required to create account)
  useEffect(() => {
    setVerificationStatus(prev => {
      if (prev.level0?.completed && prev.level0?.documents?.email && prev.level0?.documents?.phone) {
        return prev; // Already set, no need to update
      }
      return {
        ...prev,
        level0: {
          completed: true,
          documents: { email: true, phone: true }
        }
      };
    });
  }, []); // Only run once on mount

  const renderVerificationLevel = (level, title, limit, documents, levelKey) => {
    // Check if this level is locked (level 2 or 3 without complete business info)
    const isLocked = (levelKey === 'level2' || levelKey === 'level3') && !isBusinessInfoComplete;

    // Determine badge status: 'verified' (green), 'pending' (yellow), or 'incomplete' (show number)
    let badgeStatus = 'incomplete'; // 'verified', 'pending', or 'incomplete'

    if (levelKey === 'level0') {
      // Level 0 is always completed (required for account creation)
      badgeStatus = verificationStatus[levelKey]?.completed ? 'verified' : 'incomplete';
    } else {
      // Check all documents/requirements in this level
      let allVerified = true;
      let hasPending = false;
      let hasAnyProgress = false;

      documents.forEach(doc => {
        if (doc.type === 'verification') {
          // For verification type (emailVerified, phoneVerified)
          const status = verificationStatus[levelKey]?.documents?.[doc.key];
          if (status === true) {
            hasAnyProgress = true;
          } else if (status === 'PENDING' || status === 'pending') {
            hasPending = true;
            hasAnyProgress = true;
            allVerified = false;
          } else {
            allVerified = false;
          }
        } else if (doc.type === 'upload') {
          // For upload type documents
          const isUploaded = verificationStatus[levelKey]?.documents?.[doc.key] || false;
          const docStatus = documentVerificationStatus[doc.key];

          if (docStatus === true) {
            // Verified
            hasAnyProgress = true;
          } else if (isUploaded && (docStatus === false || docStatus === null)) {
            // Uploaded but pending (false means pending, null might mean uploaded but status not loaded)
            hasPending = true;
            hasAnyProgress = true;
            allVerified = false;
          } else if (isUploaded) {
            // Uploaded (has some status)
            hasAnyProgress = true;
            if (docStatus !== true) {
              allVerified = false;
            }
          } else {
            // Not uploaded
            allVerified = false;
          }
        } else if (doc.type === 'info') {
          // For info type (level0 email/phone - always true)
          hasAnyProgress = true;
        }
      });

      if (allVerified && hasAnyProgress) {
        badgeStatus = 'verified';
      } else if (hasPending || (hasAnyProgress && !allVerified)) {
        badgeStatus = 'pending';
      } else {
        badgeStatus = 'incomplete';
      }
    }

    const isCompleted = badgeStatus === 'verified';
    const isPending = badgeStatus === 'pending';

    // Add unique data-tour attribute for each level
    const tourAttr = levelKey === 'level0' ? 'settings-verification-level-0' :
      levelKey === 'level1' ? 'settings-verification-level-1' :
        levelKey === 'level2' ? 'settings-verification-level-2' :
          levelKey === 'level3' ? 'settings-verification-level-3' : null;

    return (
      <div className="invoices-card verification-card" data-tour={tourAttr} style={{
        width: '100%',
        maxWidth: '100%',
        position: 'relative',
        border: isLocked ? '2px solid var(--warning, #FFC107)' : '1px solid var(--border-primary)',
        backgroundColor: isLocked ? 'rgba(255, 193, 7, 0.03)' : 'var(--bg-primary)'
      }}>

        <div className="card-head">
          <div className="verification-header-flex">
            <div className="verification-icon-circle" style={{
              backgroundColor: isCompleted ? 'var(--success)' : (isPending ? 'var(--warning, #FFC107)' : (isLocked ? 'var(--bg-secondary)' : 'var(--bg-tertiary)')),
              color: isCompleted ? 'var(--text-inverse)' : (isPending ? 'var(--warning-text, #000000)' : 'var(--text-muted)'),
              border: (isCompleted || isPending) ? 'none' : '1px solid var(--border-primary)',
            }}>
              {isLocked ? (
                <span className="material-symbols-outlined" style={{ fontSize: isMobile ? '16px' : '14px', color: 'var(--text-muted)' }}>
                  lock
                </span>
              ) : ((isCompleted || isPending) ? '✓' : level)}
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <h3 style={{ margin: 0, fontSize: isMobile ? '1.1rem' : '1.2rem', color: isLocked ? 'var(--text-muted)' : 'var(--text-primary)', fontWeight: '700', letterSpacing: '0.02em' }}>{title}</h3>
              {levelKey === 'level0' ? (
                <p style={{ margin: '4px 0 0 0', color: 'var(--text-muted)', fontSize: isMobile ? '0.85rem' : '0.9rem' }}>
                  {t('basicVerificationInfo', {
                    ns: 'settings',
                    defaultValue: 'Included with your account.'
                  })}
                </p>
              ) : (
                <p style={{ margin: '4px 0 0 0', color: 'var(--text-muted)', fontSize: isMobile ? '0.85rem' : '0.9rem' }}>
                  {t('transactionLimit', { ns: 'settings', defaultValue: 'Transaction Limit' })}: {limit}
                </p>
              )}
            </div>
          </div>
        </div>

        <div className="verification-content-area">
          {/* Lock Banner - Show at top of content when locked */}
          {isLocked && (
            <LockedVerificationLevel
              level={level}
              isMobile={isMobile}
              onUnlockClick={() => handleUnlockClick(level)}
            />
          )}
          <div className="verification-list-grid">
            {documents.map((doc, index) => (
              <div key={doc.key || `doc-${index}`} className="verification-list-item">
                {(() => {
                  // Level 0 (Basic Verification) always shows green tick - required to create account
                  if (levelKey === 'level0') {
                    return (
                      <div style={{
                        width: '20px',
                        height: '20px',
                        borderRadius: '50%',
                        backgroundColor: 'var(--success)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        color: 'var(--text-inverse)',
                        fontSize: '12px',
                        fontWeight: '600',
                        border: 'none'
                      }}>
                        ✓
                      </div>
                    );
                  }

                  // For verification type documents (emailVerified, phoneVerified), check verification status
                  if (doc.type === 'verification') {
                    const status = verificationStatus[levelKey]?.documents?.[doc.key];
                    const isVerified = status === true;
                    const isPending = status === 'PENDING' || status === 'pending';

                    if (isVerified) {
                      return (
                        <div style={{
                          width: '20px',
                          height: '20px',
                          borderRadius: '50%',
                          backgroundColor: 'var(--success)',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          color: 'var(--text-inverse)',
                          fontSize: '12px',
                          fontWeight: '600',
                          border: 'none'
                        }}>
                          ✓
                        </div>
                      );
                    }

                    if (isPending) {
                      return (
                        <div style={{
                          width: '20px',
                          height: '20px',
                          borderRadius: '50%',
                          backgroundColor: 'var(--warning, #FFC107)',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          color: 'var(--warning-text, #000000)',
                          fontSize: '12px',
                          fontWeight: '600',
                          border: 'none'
                        }}>
                          ✓
                        </div>
                      );
                    }

                    // Not verified
                    return (
                      <div style={{
                        width: '20px',
                        height: '20px',
                        borderRadius: '50%',
                        backgroundColor: 'var(--bg-secondary)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        color: 'var(--text-muted)',
                        fontSize: '12px',
                        border: '1px solid var(--border-primary)'
                      }}>
                      </div>
                    );
                  }

                  // For upload type documents
                  // Special handling for Ghana Card which has front and back parts
                  let isUploaded = false;
                  let isVerified = false;
                  let isPending = false;
                  let isRejected = false;

                  if (doc.key === 'ghanaCardFront' || doc.key === 'ghanaCardBack') {
                    // For Ghana Card front/back, check both parts together
                    const frontUploaded = verificationStatus[levelKey]?.documents?.ghanaCardFront || false;
                    const backUploaded = verificationStatus[levelKey]?.documents?.ghanaCardBack || false;
                    // For individual parts, check if this specific part is uploaded
                    isUploaded = doc.key === 'ghanaCardFront' ? frontUploaded : backUploaded;

                    const frontStatus = normalizeDocumentStatus(documentVerificationStatus.ghanaCardFront);
                    const backStatus = normalizeDocumentStatus(documentVerificationStatus.ghanaCardBack);
                    // For individual parts, check if this specific part is verified/rejected/pending
                    const currentStatus = doc.key === 'ghanaCardFront' ? frontStatus : backStatus;
                    isVerified = currentStatus === true;
                    isPending = currentStatus === false;
                    isRejected = currentStatus === 'rejected';
                  } else {
                    // For other documents, use the standard check
                    isUploaded = verificationStatus[levelKey]?.documents?.[doc.key] || false;
                    const currentStatus = normalizeDocumentStatus(documentVerificationStatus[doc.key]);
                    isVerified = currentStatus === true;
                    isPending = currentStatus === false;
                    isRejected = currentStatus === 'rejected';
                  }

                  // Show tick only if uploaded (pending, verified, or rejected)
                  if (!isUploaded) {
                    return (
                      <div style={{
                        width: '20px',
                        height: '20px',
                        borderRadius: '50%',
                        backgroundColor: 'var(--bg-secondary)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        color: 'var(--text-muted)',
                        fontSize: '12px',
                        border: '1px solid var(--border-primary)'
                      }}>
                      </div>
                    );
                  }

                  // Show green tick for verified, yellow tick for pending, red X for rejected
                  if (isRejected) {
                    return (
                      <div style={{
                        width: '20px',
                        height: '20px',
                        borderRadius: '50%',
                        backgroundColor: 'var(--error, #dc2626)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        color: 'var(--text-inverse)',
                        fontSize: '12px',
                        fontWeight: '600',
                        border: 'none'
                      }}>
                        ✕
                      </div>
                    );
                  }

                  return (
                    <div style={{
                      width: '20px',
                      height: '20px',
                      borderRadius: '50%',
                      backgroundColor: isVerified ? 'var(--success)' : 'var(--warning, #FFC107)', // Yellow for pending
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      color: isVerified ? 'var(--text-inverse)' : 'var(--warning-text, #000000)', // Text color for yellow
                      fontSize: '12px',
                      fontWeight: '600',
                      border: 'none'
                    }}>
                      ✓
                    </div>
                  );
                })()}
                <div className="verification-item-details">
                  <p style={{ margin: 0, fontWeight: '700', color: 'var(--text-primary)', fontSize: '1.15rem', letterSpacing: '0.01em', lineHeight: '1.4' }}>{doc.name}</p>
                  {doc.description && (
                    <p style={{ margin: '4px 0 0 0', color: 'var(--text-muted)', fontSize: '0.95rem', letterSpacing: '0.01em', lineHeight: '1.6' }}>
                      {doc.description}
                    </p>
                  )}
                </div>

                {doc.type === 'upload' && (() => {
                  // Determine button text and color based on status
                  let buttonText = '';
                  let buttonColor = 'var(--accent)';
                  let isDisabled = false;

                  if (doc.key === 'ghanaCardFront' || doc.key === 'ghanaCardBack') {
                    const status = normalizeDocumentStatus(documentVerificationStatus[doc.key]);
                    const isUploaded = uploadedFiles[doc.key];
                    if (status === true) {
                      buttonText = t('verified', { ns: 'settings', defaultValue: 'Verified' });
                      buttonColor = 'var(--success)';
                      isDisabled = true;
                    } else if (status === 'rejected') {
                      buttonText = t('uploadAgain', { ns: 'settings', defaultValue: 'Upload Again' });
                      buttonColor = 'var(--error, #dc2626)';
                    } else if (isUploaded) {
                      buttonText = t('uploaded', { ns: 'settings', defaultValue: 'Uploaded' });
                      buttonColor = 'var(--warning, #FFC107)';
                    } else {
                      buttonText = `${t('upload', { ns: 'settings', defaultValue: 'Upload' })} ${doc.key === 'ghanaCardFront' ? 'Front' : 'Back'}`;
                    }
                  } else {
                    const status = normalizeDocumentStatus(documentVerificationStatus[doc.key]);
                    const isUploaded = uploadedFiles[doc.key];
                    if (status === true) {
                      buttonText = t('verified', { ns: 'settings', defaultValue: 'Verified' });
                      buttonColor = 'var(--success)';
                      isDisabled = true;
                    } else if (status === 'rejected') {
                      buttonText = t('uploadAgain', { ns: 'settings', defaultValue: 'Upload Again' });
                      buttonColor = 'var(--error, #dc2626)';
                    } else if (isUploaded) {
                      buttonText = t('uploaded', { ns: 'settings', defaultValue: 'Uploaded' });
                      buttonColor = 'var(--warning, #FFC107)';
                    } else {
                      buttonText = `${t('upload', { ns: 'settings', defaultValue: 'Upload' })} ${doc.parts?.[0] || 'Document'}`;
                    }
                  }

                  return (
                    <div data-tour="settings-verification-documents" className="verification-btn-group">
                      {doc.parts?.map((part, partIndex) => (
                        <div key={`${doc.key}_${part}_${partIndex}`} style={{ width: isMobile ? '100%' : 'auto' }}>
                          {!isLocked && (
                            <input
                              type="file"
                              id={`${doc.key}_${part}`}
                              accept="image/*,.pdf"
                              onChange={(e) => {
                                handleFileUpload(doc.key, part, e.target.files[0]);
                                // Reset file input to allow re-upload
                                e.target.value = '';
                              }}
                              style={{ display: 'none' }}
                            />
                          )}
                          <label
                            htmlFor={isLocked ? undefined : `${doc.key}_${part}`}
                            className={`verification-action-btn ${isLocked ? 'secondary' : (isDisabled && buttonColor === 'var(--success)' ? 'primary' : (isDisabled ? 'secondary' : 'primary'))}`}
                            style={{
                              backgroundColor: isLocked ? 'var(--bg-secondary)' : buttonColor,
                              color: isLocked ? 'var(--text-muted)' : (buttonColor === 'var(--success)' ? 'var(--text-inverse)' : undefined),
                              border: isLocked ? '1px solid var(--border-primary)' : undefined,
                              opacity: (uploadDocumentMutation.isPending || (isDisabled && buttonColor !== 'var(--success)')) ? 0.6 : 1,
                              cursor: (uploadDocumentMutation.isPending || isDisabled) ? 'not-allowed' : 'pointer'
                            }}
                            onClick={(e) => {
                              if (isLocked) {
                                e.preventDefault();
                                e.stopPropagation();
                                handleUnlockClick(level);
                              }
                            }}
                          >
                            {uploadDocumentMutation.isPending ? t('uploading', { ns: 'settings', defaultValue: 'Uploading...' }) : buttonText}
                          </label>
                        </div>
                      ))}
                    </div>
                  );
                })()}

                {doc.type === 'verification' && doc.key === 'emailVerified' && (
                  <div data-tour="settings-verification-email" style={{ display: 'flex', flexDirection: 'column', gap: '8px', alignItems: isMobile ? 'stretch' : 'flex-end', width: isMobile ? '100%' : 'auto' }}>
                    {showEmailTokenInput && (
                      <input
                        type="text"
                        placeholder={t('enterVerificationOTP', { ns: 'settings', defaultValue: 'Enter verification OTP' })}
                        value={emailToken}
                        onChange={(e) => setEmailToken(e.target.value)}
                        style={{
                          padding: isMobile ? '10px 12px' : '8px 12px',
                          border: '1px solid var(--border-secondary)',
                          borderRadius: '6px',
                          fontSize: isMobile ? '0.9rem' : '0.9rem',
                          backgroundColor: 'var(--bg-input)',
                          color: 'var(--text-primary)',
                          width: isMobile ? '100%' : '200px'
                        }}
                      />
                    )}
                    <div className="verification-btn-group info">
                      {!verificationStatus.level1?.documents?.emailVerified && !showEmailTokenInput && (
                        <button
                          onClick={handleRequestEmailVerification}
                          disabled={isRequestingEmailVerification}
                          className="verification-action-btn secondary"
                        >
                          {isRequestingEmailVerification ? t('sending', { ns: 'settings', defaultValue: 'Sending...' }) : t('resendEmail', { ns: 'settings', defaultValue: 'Resend Email' })}
                        </button>
                      )}
                      <button
                        onClick={handleEmailVerification}
                        disabled={verificationStatus.level1?.documents?.emailVerified === true || verificationStatus.level1?.documents?.emailVerified === 'pending' || verificationStatus.level1?.documents?.emailVerified === 'PENDING' || isVerifyingEmail}
                        className="verification-action-btn primary"
                        style={{
                          backgroundColor: verificationStatus.level1?.documents?.emailVerified === true ? 'var(--success)' : ((verificationStatus.level1?.documents?.emailVerified === 'pending' || verificationStatus.level1?.documents?.emailVerified === 'PENDING') ? 'var(--warning, #FFC107)' : undefined),
                          color: (verificationStatus.level1?.documents?.emailVerified === 'pending' || verificationStatus.level1?.documents?.emailVerified === 'PENDING') ? 'var(--warning-text, #000000)' : undefined,
                        }}
                      >
                        {isVerifyingEmail ? t('verifying', { ns: 'settings', defaultValue: 'Verifying...' }) : verificationStatus.level1?.documents?.emailVerified === true ? t('verified', { ns: 'settings' }) : (verificationStatus.level1?.documents?.emailVerified === 'pending' || verificationStatus.level1?.documents?.emailVerified === 'PENDING') ? t('pending', { ns: 'settings', defaultValue: 'Pending' }) : showEmailTokenInput ? t('verifyOTP', { ns: 'settings', defaultValue: 'Verify OTP' }) : t('verifyEmail', { ns: 'settings', defaultValue: 'Verify Email' })}
                      </button>
                    </div>
                  </div>
                )}

                {doc.type === 'verification' && doc.key === 'phoneVerified' && (
                  <div data-tour="settings-verification-phone" style={{ display: 'flex', flexDirection: 'column', gap: '8px', alignItems: isMobile ? 'stretch' : 'flex-end', width: isMobile ? '100%' : 'auto' }}>
                    {showPhoneOtpInput && (
                      <input
                        type="text"
                        placeholder={t('enterVerificationOTP', { ns: 'settings', defaultValue: 'Enter verification OTP' })}
                        value={phoneOtp}
                        onChange={(e) => setPhoneOtp(e.target.value)}
                        maxLength={6}
                        style={{
                          padding: isMobile ? '12px' : '10px',
                          border: '1px solid var(--border-secondary)',
                          borderRadius: '6px',
                          fontSize: isMobile ? '16px' : '14px',
                          backgroundColor: 'var(--bg-input)',
                          color: 'var(--text-primary)',
                          width: isMobile ? '100%' : '200px',
                          marginBottom: isMobile ? '0' : '8px',
                          textAlign: 'center'
                        }}
                      />
                    )}
                    <div className="verification-btn-group info">
                      {!verificationStatus.level1?.documents?.phoneVerified && showPhoneOtpInput && (
                        <button
                          onClick={async () => {
                            try {
                              const response = await authService.requestVerifyPhoneOtp();
                              if (response?.code === '00') {
                                success(t('otpSentToPhone', { ns: 'settings', defaultValue: '✓ OTP sent! Please check your phone.' }));
                              } else {
                                showError(response?.message || t('pleaseTryAgain', { ns: 'settings', defaultValue: 'Please try again.' }));
                              }
                            } catch (error) {
                              logger.error('Failed to resend phone OTP', { error });
                              showError(t('pleaseTryAgain', { ns: 'settings', defaultValue: 'Please try again.' }));
                            }
                          }}
                          className="verification-action-btn secondary"
                        >
                          {t('resendOTP', { ns: 'settings', defaultValue: 'Resend OTP' })}
                        </button>
                      )}
                      <button
                        onClick={handlePhoneVerification}
                        disabled={verificationStatus.level1?.documents?.phoneVerified === true || verificationStatus.level1?.documents?.phoneVerified === 'pending' || verificationStatus.level1?.documents?.phoneVerified === 'PENDING' || isVerifyingPhone}
                        className="verification-action-btn primary"
                        style={{
                          backgroundColor: verificationStatus.level1?.documents?.phoneVerified === true ? 'var(--success)' : ((verificationStatus.level1?.documents?.phoneVerified === 'pending' || verificationStatus.level1?.documents?.phoneVerified === 'PENDING') ? 'var(--warning, #FFC107)' : undefined),
                          color: (verificationStatus.level1?.documents?.phoneVerified === 'pending' || verificationStatus.level1?.documents?.phoneVerified === 'PENDING') ? 'var(--warning-text, #000000)' : undefined,
                        }}
                      >
                        {isVerifyingPhone ? t('verifying', { ns: 'settings', defaultValue: 'Verifying...' }) : verificationStatus.level1?.documents?.phoneVerified === true ? t('verified', { ns: 'settings' }) : (verificationStatus.level1?.documents?.phoneVerified === 'pending' || verificationStatus.level1?.documents?.phoneVerified === 'PENDING') ? t('pending', { ns: 'settings', defaultValue: 'Pending' }) : showPhoneOtpInput ? t('verifyOTP', { ns: 'settings', defaultValue: 'Verify OTP' }) : t('sendOTP', { ns: 'settings', defaultValue: 'Send OTP' })}
                      </button>
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  };

  const verificationLevels = useMemo(() => [
    {
      level: 0,
      title: t('basicAccount', { ns: 'settings', defaultValue: 'Basic Account' }),
      limit: 'GHS 1,000',
      key: 'level0',
      documents: [
        { name: t('accountCreated', { ns: 'settings', defaultValue: 'Account Created' }), key: 'accountCreated', type: 'info', description: t('accountCreatedDesc', { ns: 'settings', defaultValue: 'Your account was successfully created.' }) },
        { name: t('basicInformation', { ns: 'settings', defaultValue: 'Basic Information' }), key: 'basicInfo', type: 'info', description: t('basicInfoDesc', { ns: 'settings', defaultValue: 'Email and phone number provided.' }) }
      ]
    },
    {
      level: 1,
      title: t('emailPhoneVerified', { ns: 'settings', defaultValue: 'Email & Phone Verified' }),
      limit: 'GHS 5,000',
      key: 'level1',
      documents: [
        { name: t('emailVerification', { ns: 'settings', defaultValue: 'Email Verification' }), key: 'emailVerified', type: 'verification', description: t('verifyEmailAddress', { ns: 'settings', defaultValue: 'Verify email address' }) },
        { name: t('phoneVerification', { ns: 'settings', defaultValue: 'Phone Verification' }), key: 'phoneVerified', type: 'verification', description: t('verifyPhoneNumberOTP', { ns: 'settings', defaultValue: 'Verify phone number with OTP' }) }
      ]
    },
    {
      level: 2,
      title: t('idVerification', { ns: 'settings', defaultValue: 'ID Verification' }),
      limit: 'GHS 20,000',
      key: 'level2',
      documents: [
        {
          name: t('certificateOfIncorporation', { ns: 'settings', defaultValue: 'Certificate of Incorporation' }),
          key: 'coiDoc',
          type: 'upload',
          description: t('businessRegistrationCertificate', { ns: 'settings', defaultValue: 'Business registration certificate' }),
          parts: ['document']
        },
        {
          name: t('ghanaCardFront', { ns: 'settings', defaultValue: 'Ghana Card Front' }),
          key: 'ghanaCardFront',
          type: 'upload',
          description: t('ghanaCardFrontDescription', { ns: 'settings', defaultValue: 'Government-issued National ID front' }),
          parts: ['document']
        },
        {
          name: t('ghanaCardBack', { ns: 'settings', defaultValue: 'Ghana Card Back' }),
          key: 'ghanaCardBack',
          type: 'upload',
          description: t('ghanaCardBackDescription', { ns: 'settings', defaultValue: 'Government-issued National ID back' }),
          parts: ['document']
        },
        {
          name: t('businessRegistrationCertificate', { ns: 'settings', defaultValue: 'Business Registration Certificate' }),
          key: 'brcDoc',
          type: 'upload',
          description: t('businessRegistrationDocument', { ns: 'settings', defaultValue: 'Business registration document' }),
          parts: ['document']
        }
      ]
    },
    {
      level: 3,
      title: t('fullKYC', { ns: 'settings', defaultValue: 'Full KYC' }),
      limit: 'GHS 100,000',
      key: 'level3',
      documents: [
        {
          name: t('businessLicense', { ns: 'settings', defaultValue: 'Business License' }),
          key: 'blDoc',
          type: 'upload',
          description: t('businessLicenseDocument', { ns: 'settings', defaultValue: 'Business license document' }),
          parts: ['document']
        },
        {
          name: t('operatingPermit', { ns: 'settings', defaultValue: 'Operating Permit' }),
          key: 'opDoc',
          type: 'upload',
          description: t('operatingPermitDocument', { ns: 'settings', defaultValue: 'Operating permit document' }),
          parts: ['document']
        },
        {
          name: t('proofOfAddress', { ns: 'settings', defaultValue: 'Proof of Address' }),
          key: 'proofOfAddress',
          type: 'upload',
          description: t('proofOfAddressDescription', { ns: 'settings', defaultValue: 'Utility bill or bank statement (max 3 months old)' }),
          parts: ['document']
        }
      ]
    }
  ], [t]);

  // Show loading spinner while initial data is loading
  if (isInitialLoading) {
    return (
      <div style={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        minHeight: '60vh',
        padding: '40px 20px',
        textAlign: 'center'
      }}>
        <div style={{
          width: '48px',
          height: '48px',
          border: '4px solid var(--border-primary)',
          borderTop: '4px solid var(--accent)',
          borderRadius: '50%',
          animation: 'spin 1s linear infinite'
        }} />
      </div>
    );
  }

  return (
    <>
      {/* Business Information Required Modal */}
      <BusinessInfoRequiredModal
        isOpen={showBusinessInfoModal}
        onClose={() => {
          setShowBusinessInfoModal(false);
          setLockedLevel(null);
        }}
        level={lockedLevel}
      />

      <div className="invoices-card">
        <div className="card-head">
          <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
            <div style={{
              width: '56px',
              height: '56px',
              borderRadius: '14px',
              background: 'linear-gradient(135deg, var(--accent) 0%, var(--accent-hover) 100%)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              boxShadow: 'var(--shadow-md)'
            }}>
              <span className="material-symbols-outlined" style={{ fontSize: '32px', color: 'white' }}>
                verified_user
              </span>
            </div>
            <div>
              <h3 style={{ margin: 0, fontSize: '24px', fontWeight: '700', color: 'var(--text-primary)' }}>
                {t('businessVerification', { ns: 'settings', defaultValue: 'Business Verification' })}
              </h3>
              <p style={{ color: 'var(--text-muted)', margin: 0, fontSize: '14px', fontWeight: '500' }}>
                {t('completeVerificationProcess', { ns: 'settings', defaultValue: 'Complete the verification process to unlock higher transaction limits and additional features.' })}
              </p>
            </div>
          </div>
        </div>

        <div style={{ padding: '24px' }}>
          <div className="verification-content-area">
            {/* Guidelines Card */}
            <div style={{
              padding: isMobile ? '16px' : '20px',
              backgroundColor: 'var(--info-bg)',
              border: '1px solid var(--info)',
              borderRadius: 'var(--radius-md)',
              marginBottom: '32px'
            }} data-tour="settings-verification-guidelines">
              <h4 style={{
                color: 'var(--info)',
                marginBottom: '16px',
                display: 'flex',
                alignItems: 'center',
                gap: '8px',
                fontSize: isMobile ? '1rem' : '1.1rem'
              }}>
                <span className="material-symbols-outlined" style={{ fontSize: isMobile ? '20px' : '24px' }}>info</span>
                {t('verificationGuidelines', { ns: 'settings', defaultValue: 'Verification Guidelines' })}
              </h4>
              <div style={{ textAlign: 'left' }}>
                <ul style={{
                  color: 'var(--text-primary)',
                  lineHeight: '1.6',
                  paddingLeft: '20px',
                  margin: 0,
                  fontSize: isMobile ? '0.85rem' : '0.9rem'
                }}>
                  <li>{t('documentsMustBeClear', { ns: 'settings', defaultValue: 'All documents must be clear, legible, and in color' })}</li>
                  <li>{t('ghanaCardFourCorners', { ns: 'settings', defaultValue: 'Ghana Card should show all four corners clearly' })}</li>
                  <li>{t('proofOfAddress3Months', { ns: 'settings', defaultValue: 'Proof of address should be dated within the last 3 months' })}</li>
                  <li>{t('fileSizeLimit5MB', { ns: 'settings', defaultValue: 'File size limit: 5MB per document' })}</li>
                  <li>{t('supportedFormats', { ns: 'settings', defaultValue: 'Supported formats: JPG, PNG, PDF' })}</li>
                </ul>
              </div>
            </div>

            {/* Verification Progress Guide - Shows current level, next steps, and features */}
            <VerificationProgressGuide
              verificationStatus={verificationStatus}
              documentVerificationStatus={documentVerificationStatus}
              isMobile={isMobile}
            />

            {/* Verification Levels */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: isMobile ? '16px' : '32px', marginTop: '32px' }}>
              {verificationLevels.map((level, index) => (
                <div key={level.key || `level-${level.level}-${index}`}>
                  {renderVerificationLevel(
                    level.level,
                    level.title,
                    level.limit,
                    level.documents,
                    `level${level.level}`
                  )}
                </div>
              ))}
            </div>

            {/* Next Steps / What to Do Next Component */}
            <VerificationNextSteps
              verificationStatus={verificationStatus}
              documentVerificationStatus={documentVerificationStatus}
              isMobile={isMobile}
            />
          </div>
        </div>
      </div>
    </>
  );
};

export default Verification;
