/**
 * Locked Verification Level Component
 * 
 * Displays a locked state indicator for verification levels that require
 * business information to be completed before unlocking.
 */

import React from 'react';
import { useTranslation } from 'react-i18next';

const LockedVerificationLevel = ({ level, isMobile, onUnlockClick }) => {
  const { t } = useTranslation();

  return (
    <>
      {/* Lock Banner at Top - Always visible so users can see requirements */}
      <div
        style={{
          padding: isMobile ? '12px 16px' : '14px 20px',
          backgroundColor: 'var(--warning-bg, rgba(255, 193, 7, 0.15))',
          borderBottom: '2px solid var(--warning, #FFC107)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          gap: '12px',
          cursor: 'pointer',
          transition: 'all 0.2s ease'
        }}
        onClick={onUnlockClick}
        onMouseOver={(e) => {
          e.currentTarget.style.backgroundColor = 'var(--warning-bg, rgba(255, 193, 7, 0.2))';
        }}
        onMouseOut={(e) => {
          e.currentTarget.style.backgroundColor = 'var(--warning-bg, rgba(255, 193, 7, 0.15))';
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1 }}>
          <span className="material-symbols-outlined" style={{
            fontSize: '24px',
            color: 'var(--warning, #FFC107)',
            flexShrink: 0
          }}>
            lock
          </span>
          <div style={{ flex: 1 }}>
            <p style={{
              margin: 0,
              fontWeight: '600',
              color: 'var(--text-primary)',
              fontSize: isMobile ? '0.9rem' : '1rem',
              marginBottom: '2px'
            }}>
              {t('levelLockedCompleteBusinessInfo', { ns: 'settings', defaultValue: 'Level Locked - Complete Business Information Required' })}
            </p>
            <p style={{
              margin: 0,
              color: 'var(--text-secondary)',
              fontSize: isMobile ? '0.8rem' : '0.85rem'
            }}>
              {t('clickToSeeRequirements', { ns: 'settings', defaultValue: 'Click to see required fields and unlock this level' })}
            </p>
          </div>
        </div>
        <span className="material-symbols-outlined" style={{
          fontSize: '20px',
          color: 'var(--warning, #FFC107)',
          flexShrink: 0
        }}>
          chevron_right
        </span>
      </div>

    </>
  );
};

export default LockedVerificationLevel;
