/**
 * useIsMounted Hook
 * 
 * React hook to track if a component is still mounted.
 * Useful for preventing state updates on unmounted components.
 * Returns a stable function reference that can be safely used in dependency arrays.
 * 
 * @returns {Function} Function that returns true if component is mounted
 * 
 * @example
 * const isMounted = useIsMounted();
 * 
 * useEffect(() => {
 *   async function fetchData() {
 *     const data = await api.getData();
 *     if (isMounted()) {
 *       setData(data);
 *     }
 *   }
 *   fetchData();
 * }, []); // isMounted doesn't need to be in deps - it's stable
 */
import { useRef, useEffect, useCallback } from 'react';

export const useIsMounted = () => {
  const isMountedRef = useRef(true);

  useEffect(() => {
    isMountedRef.current = true;
    return () => {
      isMountedRef.current = false;
    };
  }, []);

  // Use useCallback to ensure stable function reference
  return useCallback(() => isMountedRef.current, []);
};

export default useIsMounted;

